import re, glob, os
chapter_files = sorted(glob.glob('blueprint/src/chapters/*.tex'))
# label inside block: a \label{...} not preceded by '%'
# uses{...} too. plasTeX's depgraph reads them inside thm/def/lemma blocks. Approximation: process all label/uses lines that are not in commented-out lines.
edges = {}     # node -> set of predecessor (uses)
labels = []
current_label = None
in_block = False
for f in chapter_files:
    cf = open(f).read()
    # walk line-by-line tracking last \label{...} as the current node, until end of block (rough: until next \label or end of file)
    last_label = None
    for ln_no, line in enumerate(cf.splitlines(), 1):
        # ignore commented lines for purposes of label/uses
        stripped = line.lstrip()
        if stripped.startswith('%'):
            continue
        for lab in re.findall(r'\\label\{([^}]+)\}', line):
            last_label = lab
            edges.setdefault(lab, set())
            labels.append((lab, f, ln_no))
        for usesb in re.findall(r'\\uses\{([^}]+)\}', line):
            if last_label is None:
                continue
            for u in [x.strip() for x in usesb.split(',') if x.strip()]:
                edges.setdefault(last_label, set()).add(u)
# find cycles via DFS
WHITE, GRAY, BLACK = 0,1,2
color = {n:WHITE for n in edges}
cycles = []
def dfs(node, stack):
    color[node] = GRAY
    stack.append(node)
    for nb in edges.get(node, ()):
        if nb not in color:
            color[nb] = WHITE
        if color[nb] == GRAY:
            i = stack.index(nb) if nb in stack else 0
            cycles.append(stack[i:] + [nb])
        elif color[nb] == WHITE:
            dfs(nb, stack)
    stack.pop()
    color[node] = BLACK
for n in list(edges):
    if color[n] == WHITE:
        dfs(n, [])
print("Total labels:", len(edges))
print("Cycles found:", len(cycles))
for c in cycles[:20]:
    print(" -> ".join(c))
